import React, { useState, useRef, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Text, Float, OrbitControls, Stars } from '@react-three/drei';
import * as THREE from 'three';

// Individual Skill Icon Component
function SkillIcon({ icon, name, position, index, total, hoveredSkill, setHoveredSkill }) {
  const meshRef = useRef();
  const [hovered, setHovered] = useState(false);

  useFrame(({ clock }) => {
    if (meshRef.current) {
      // Gentle floating animation
      meshRef.current.position.y = position[1] + Math.sin(clock.elapsedTime * 0.5 + index) * 0.15;
      meshRef.current.rotation.z = Math.sin(clock.elapsedTime * 0.3 + index) * 0.05;
    }
  });

  const handleHover = (isHovered) => {
    setHovered(isHovered);
    setHoveredSkill(isHovered ? name : null);
  };

  return (
    <Float
      speed={1 + Math.random() * 0.5}
      rotationIntensity={0.2}
      floatIntensity={0.3}
    >
      <mesh
        ref={meshRef}
        position={position}
        onPointerOver={() => handleHover(true)}
        onPointerOut={() => handleHover(false)}
        scale={hovered || hoveredSkill === name ? 1.3 : 0.8}
      >
        <circleGeometry args={[0.6, 32]} />
        <meshBasicMaterial
          color={hovered || hoveredSkill === name ? '#7c3aed' : '#4a4a6a'}
          transparent
          opacity={hovered || hoveredSkill === name ? 0.9 : 0.5}
          side={THREE.DoubleSide}
        />
        <Text
          position={[0, 0, 0.01]}
          fontSize={0.5}
          color="white"
          anchorX="center"
          anchorY="middle"
          font="/fonts/Inter_18pt-Bold.ttf"
        >
          {icon}
        </Text>
        {hovered || hoveredSkill === name && (
          <Text
            position={[0, -1.2, 0]}
            fontSize={0.2}
            color="#a78bfa"
            anchorX="center"
            anchorY="middle"
          >
            {name}
          </Text>
        )}
      </mesh>
    </Float>
  );
}

// Main Skills Component
const Skills = () => {
  const [hoveredSkill, setHoveredSkill] = useState(null);

  const allSkills = [
    { name: 'HTML5', icon: '🌐', category: 'Frontend' },
    { name: 'CSS3', icon: '🎨', category: 'Frontend' },
    { name: 'JavaScript', icon: '⚡', category: 'Frontend' },
    { name: 'TypeScript', icon: '📘', category: 'Frontend' },
    { name: 'React', icon: '⚛️', category: 'Frontend' },
    { name: 'Next.js', icon: '▲', category: 'Frontend' },
    { name: 'Tailwind CSS', icon: '💨', category: 'Frontend' },
    { name: 'Redux', icon: '🔄', category: 'Frontend' },
    { name: 'Framer Motion', icon: '🎬', category: 'Frontend' },
    { name: 'Node.js', icon: '🟢', category: 'Backend' },
    { name: 'Express.js', icon: '🚀', category: 'Backend' },
    { name: 'MongoDB', icon: '🍃', category: 'Backend' },
    { name: 'MySQL', icon: '🐬', category: 'Backend' },
    { name: 'PostgreSQL', icon: '🐘', category: 'Backend' },
    { name: 'Firebase', icon: '🔥', category: 'Backend' },
    { name: 'JWT', icon: '🔐', category: 'Backend' },
    { name: 'REST API', icon: '🔗', category: 'Backend' },
    { name: 'Socket.io', icon: '📡', category: 'Backend' },
    { name: 'Java', icon: '☕', category: 'Languages' },
    { name: 'Python', icon: '🐍', category: 'Languages' },
    { name: 'C++', icon: '⚙️', category: 'Languages' },
    { name: 'C', icon: '🔧', category: 'Languages' },
    { name: 'C#', icon: '🎯', category: 'Languages' },
    { name: 'PHP', icon: '🐘', category: 'Languages' },
    { name: 'Git', icon: '🔀', category: 'Tools' },
    { name: 'GitHub', icon: '🐙', category: 'Tools' },
    { name: 'Docker', icon: '🐳', category: 'Tools' },
    { name: 'Linux', icon: '🐧', category: 'Tools' },
    { name: 'VS Code', icon: '💻', category: 'Tools' },
    { name: 'Postman', icon: '📮', category: 'Tools' },
    { name: 'Figma', icon: '🎯', category: 'Tools' }
  ];

  // Generate positions in a circle
  const generatePositions = (count) => {
    const positions = [];
    const radius = 3.5;
    const total = count;

    for (let i = 0; i < total; i++) {
      const angle = (i / total) * Math.PI * 2;
      // Add slight randomness to positions
      const r = radius + (Math.random() - 0.5) * 0.8;
      const x = Math.cos(angle) * r;
      const z = Math.sin(angle) * r;
      const y = (Math.random() - 0.5) * 1.5;
      positions.push([x, y, z]);
    }
    return positions;
  };

  const positions = useMemo(() => generatePositions(allSkills.length), []);

  // Rotating Scene
  function RotatingScene() {
    const groupRef = useRef();

    useFrame(({ clock }) => {
      if (groupRef.current) {
        groupRef.current.rotation.y = clock.elapsedTime * 0.08;
        groupRef.current.rotation.x = Math.sin(clock.elapsedTime * 0.03) * 0.05;
      }
    });

    return (
      <group ref={groupRef}>
        {allSkills.map((skill, index) => (
          <SkillIcon
            key={skill.name}
            icon={skill.icon}
            name={skill.name}
            position={positions[index]}
            index={index}
            total={allSkills.length}
            hoveredSkill={hoveredSkill}
            setHoveredSkill={setHoveredSkill}
          />
        ))}
      </group>
    );
  }

  return (
    <section id="skills" className="relative z-10 py-16 px-6 overflow-hidden min-h-screen">
      <div className="max-w-6xl mx-auto">
        <h2 className="text-sm uppercase tracking-widest text-gray-500 font-semibold mb-8">My Skills</h2>

        <div className="relative w-full h-[600px] rounded-3xl overflow-hidden bg-gradient-to-br from-[#0a0a0f] via-[#0d0d1a] to-[#0a0a0f]">
          <Canvas
            camera={{ position: [0, 0, 8], fov: 50 }}
            gl={{ antialias: true, alpha: true }}
          >
            <ambientLight intensity={0.5} />
            <pointLight position={[10, 10, 10]} intensity={0.5} />
            <pointLight position={[-10, -10, -10]} intensity={0.3} color="#7c3aed" />

            {/* Stars Background */}
            <Stars
              radius={20}
              depth={20}
              count={2000}
              factor={4}
              saturation={0.3}
              fade
              speed={0.5}
            />

            {/* Rotating Skill Icons */}
            <RotatingScene />

            {/* Controls */}
            <OrbitControls
              enableZoom={false}
              enablePan={false}
              autoRotate={false}
              enableRotate={false}
            />
          </Canvas>

          {/* Category Labels */}
          <div className="absolute bottom-4 left-4 right-4 flex justify-center gap-6 flex-wrap pointer-events-none">
